body.script:
fetch('catalog.xml')
    .then(response => response.text())
    .then(data => {
        const parser = new DOMParser();
        const xml = parser.parseFromString(data, "application/xml");
        const products = xml.getElementsByTagName("product");

        let table = document.getElementById("productTable");

        for (let i = 0; i < products.length; i++) {
            let row = table.insertRow();

            let id = products[i].getAttribute("id");
            let name = products[i].getElementsByTagName("name")[0].textContent;
            let category = products[i].getElementsByTagName("category")[0].textContent;
            let price = products[i].getElementsByTagName("price")[0].textContent;
            let stock = products[i].getElementsByTagName("stock")[0].textContent;

            row.insertCell(0).innerHTML = id;
            row.insertCell(1).innerHTML = name;
            row.insertCell(2).innerHTML = category;
            row.insertCell(3).innerHTML = price;
            row.insertCell(4).innerHTML = stock;
        }
    });
